INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b6f0b2c9-c82e-46fe-90df-5453a28bb5c9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Security Hardening — CORS, Rate Limiting, Headers, and Injection Prevention$escape$,
  $escape$Django ships with solid defaults, but production security requires explicit configuration. For CORS, use `django-cors-headers`: set `CORS_ALLOWED_ORIGINS` to an explicit list — never `CORS_ALLOW_ALL_ORIGINS = True` in production. Pair it with `CORS_ALLOW_CREDENTIALS = False` unless your auth flow demands otherwise.

For rate limiting, `django-ratelimit` gives you decorator-level control. Use `@ratelimit(key='ip', rate='20/m', block=True)` on login and registration views to blunt brute-force attacks.

Security headers are handled by `django-csp` for Content-Security-Policy and Django's built-ins: set `SECURE_BROWSER_XSS_FILTER`, `X_FRAME_OPTIONS = 'DENY'`, `SECURE_CONTENT_TYPE_NOSNIFF = True`, and `SECURE_HSTS_SECONDS = 31536000` in settings.

For injection prevention, never interpolate user input into raw SQL — use the ORM or `cursor.execute()` with parameterized queries. Django's ORM escapes values automatically, but `RawQuerySet` and `extra()` are foot-guns. Validate all external input with serializers or `django.core.validators` before it touches the database layer.$escape$,
  $escape$# settings.py — production security baseline
CORS_ALLOWED_ORIGINS = ["https://app.example.com"]
CORS_ALLOW_CREDENTIALS = False

SECURE_BROWSER_XSS_FILTER = True
SECURE_CONTENT_TYPE_NOSNIFF = True
X_FRAME_OPTIONS = "DENY"
SECURE_HSTS_SECONDS = 31536000
SECURE_HSTS_INCLUDE_SUBDOMAINS = True

# views.py — rate-limit login endpoint
from django_ratelimit.decorators import ratelimit

@ratelimit(key="ip", rate="10/m", block=True)
def login_view(request):
    ...$escape$,
