INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a03556d5-4ee7-4878-a7ae-061f3d116852',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Performance Trio: Connection Pooling, Async Views, and GZip Middleware$escape$,
  $escape$Django's default database layer opens a new connection per request unless you configure pooling. Use `django-db-geventpool` or PgBouncer externally, or set `CONN_MAX_AGE` in `DATABASES` to reuse connections — `CONN_MAX_AGE=60` keeps each thread's connection alive for 60 seconds, eliminating per-request TCP handshakes.

For I/O-bound views, Django's native async support (3.1+) lets you define `async def` views and use `sync_to_async` to wrap ORM calls. Pair this with an ASGI server like Uvicorn or Daphne — running under WSGI silently downgrades async views to sync execution.

Response compression is handled by `django.middleware.gzip.GZipMiddleware`. Add it near the top of `MIDDLEWARE` (above `SessionMiddleware`) so it wraps the full response. For streaming responses, use `StreamingHttpResponse` with `GZipMiddleware` — it chunks the output, keeping memory overhead flat.

Combined: persistent DB connections reduce latency, async views increase throughput under I/O load, and GZip cuts payload size — three levers that compose cleanly without external dependencies.$escape$,
  $escape$# settings.py
DATABASES = {
    "default": {
        "ENGINE": "django.db.backends.postgresql",
        "CONN_MAX_AGE": 60,  # seconds; 0 = close after each request
    }
}

MIDDLEWARE = [
    "django.middleware.gzip.GZipMiddleware",  # must be near top
    "django.middleware.common.CommonMiddleware",
    # ...
]

# views.py
from asgiref.sync import sync_to_async
from django.http import JsonResponse

async def article_list(request):
    articles = await sync_to_async(list)(Article.objects.select_related("author").all()[:20])
    return JsonResponse({"results": [a.title for a in articles]})$escape$,
  $escape$python$escape$,
