INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c7fee759-6f9f-4cb2-aa21-2163803ec246',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django REST Framework — Versioning, URL Structure, and Auto OpenAPI Docs$escape$,
  $escape$Django REST Framework ships with four versioning schemes. `URLPathVersioning` is the most explicit — it embeds the version in the URL (`/api/v1/users/`) and makes routing unambiguous. Configure it globally in `REST_FRAMEWORK` settings via `DEFAULT_VERSIONING_CLASS` and `ALLOWED_VERSIONS`, then access `request.version` inside any `APIView` or `ViewSet` to branch behavior without forking serializers unnecessarily.

For OpenAPI generation, DRF 3.14+ includes `drf-spectacular` as the community standard. Add `SpectacularAPIView` and `SpectacularSwaggerView` to `urlpatterns` for interactive docs. Annotate non-obvious endpoints with `@extend_schema(parameters=[...], responses={200: MySerializer})` — this keeps the schema accurate without writing YAML by hand.

Avoid versioning via query params (`?version=1`) — it breaks HTTP caching and makes URL semantics unclear. Accept headers (`AcceptHeaderVersioning`) are REST-pure but harder to test in browsers. Stick with URL path versioning for public APIs, namespace your routers per version, and deprecate old versions by returning a `Deprecation` response header alongside a sunset date.$escape$,
  $escape$# settings.py
REST_FRAMEWORK = {
    "DEFAULT_VERSIONING_CLASS": "rest_framework.versioning.URLPathVersioning",
    "DEFAULT_VERSION": "v1",
    "ALLOWED_VERSIONS": ["v1", "v2"],
}

# urls.py
from drf_spectacular.views import SpectacularAPIView, SpectacularSwaggerView

urlpatterns = [
    path("api/<version>/schema/", SpectacularAPIView.as_view(), name="schema"),
    path("api/<version>/docs/", SpectacularSwaggerView.as_view(url_name="schema"), name="swagger-ui"),
]

# views.py
from drf_spectacular.utils import extend_schema

class UserViewSet(viewsets.ModelViewSet):
    @extend_schema(responses={200: UserSerializer, 410: None})
    def list(self, request, *args, **kwargs):
        if request.version == "v1":
            return super().list(request, *args, **kwargs)
        return Response(status=410)  # Gone — force upgrade$escape$,
  $escape$python$escape$,
