INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b5549d81-b194-43e0-8847-98161c2b5b5d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Django Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$Django doesn't ship with health check or metrics endpoints out of the box, but the ecosystem fills the gap cleanly. `django-health-check` lets you register checks (database, cache, storage, custom) under a single `/health/` view by adding `health_check` and its sub-apps to `INSTALLED_APPS` and wiring `HealthCheckView` in `urls.py`. For Prometheus metrics, `django-prometheus` instruments your models, views, migrations, and DB queries automatically — just prepend `django_prometheus.middleware.PrometheusBeforeMiddleware` and append `PrometheusAfterMiddleware`, then expose `/metrics/`. For distributed tracing, `opentelemetry-instrumentation-django` hooks into Django's request/response cycle via `DjangoInstrumentor().instrument()`, automatically propagating W3C trace context across services. Pair it with `opentelemetry-instrumentation-psycopg2` to get DB span visibility. All three integrate with Gunicorn and `ASGI` deployments — call `DjangoInstrumentor` in `AppConfig.ready()` rather than `settings.py` to avoid double-instrumentation in multi-worker setups. Use `HEALTH_CHECK` dict in settings to configure thresholds like disk usage warnings.$escape$,
  $escape$# apps.py
from django.apps import AppConfig
from opentelemetry.instrumentation.django import DjangoInstrumentor
from opentelemetry.instrumentation.psycopg2 import Psycopg2Instrumentor

class CoreConfig(AppConfig):
    name = 'core'

    def ready(self):
        DjangoInstrumentor().instrument()
        Psycopg2Instrumentor().instrument()

# urls.py
from health_check.views import MainView
from django_prometheus import exports

urlpatterns = [
    path('health/', MainView.as_view()),
    path('metrics/', exports.ExportToDjangoView),
]$escape$,
  $escape$python$escape$,
